#include <unordered_map>

class CountIntervals {
public:
    CountIntervals() {}

    void add(int left, int right) {
        unordered_map<int, int> intervals;
        for (int i = left; i <= right; i++) {
            intervals[i]++;
        }
    }

    int count() {
        int result = 0;
        for (auto it = intervals.begin(); it != intervals.end(); it++) {
            result += it->second;
        }
        return result;
    }
};
```

